const Map<String, int> _recommendedCountOverrides = {
  "Al-Bari'": 129,
  'Al-Fattah': 489,
};

int? _recommendedCountFor(String transliteration) {
  return _recommendedCountOverrides[transliteration];
}


final List<AsmaName> asmaNames = (() {
  final arabic = _parts(_arabic);
  final latin = _parts(_latin);
  final localized = <String, List<String>>{
    for (final entry in _meanings.entries) entry.key: _parts(entry.value),
  };

  if (arabic.length != 99 || latin.length != 99) {
    throw StateError('Asma data must contain exactly 99 names.');
  }

  for (final entry in localized.entries) {
    if (entry.value.length != 99) {
      throw StateError('${entry.key} meanings must contain exactly 99 items.');
    }
  }

  return List<AsmaName>.generate(99, (index) {
    return AsmaName(
      number: index + 1,
      arabic: arabic[index],
      transliteration: latin[index],
      meanings: {
        for (final entry in localized.entries) entry.key: entry.value[index],
      },
      recommendedCount: _recommendedCountFor(latin[index]),
    );
  }, growable: false);
})();
